  INSERT INTO consentimientos (tratamiento_id, titulo, texto_consentimiento, cuidados_pre, cuidados_post, activo)
  VALUES (28, 'Consentimiento Informado · Rellenos y Bioestimuladores', 'DESCRIPCIÓN DEL PROCEDIMIENTO Los rellenos dérmicos de ácido hialurónico (HA) son geles biocompatibles inyectables que restauran volumen, suavizan surcos, definen contornos y mejoran la hidratación profunda del tejido. Dependiendo de la densidad del producto y la zona tratada, la duración varía de 6 meses a 2 años. El procedimiento puede incluir también bioestimuladores de colágeno (Sculptra, Radiesse, PDO) o hilos de sustentación según el plan individualizado. BENEFICIOS ESPERADOS ✓ Restauración de volumen en pómulos, labios, mentón, sienes y manos. ✓ Suavización de surcos (nasogeniano, lagrimal, marioneta). ✓ Definición y perfilamiento del contorno facial y mandibular. ✓ Hidratación profunda y mejora de la calidad de la piel. ✓ Corrección de asimetrías faciales. ✓ Rejuvenecimiento facial natural sin cirugía. RIESGOS Y POSIBLES COMPLICACIONES RIESGOS MENORES (FRECUENTES Y TRANSITORIOS) ▸ Edema local de 24 a 72 horas; puede persistir hasta 2 semanas en labios. ▸ Hematoma o equimosis: se resuelve en 5 a 14 días. ▸ Eritema y sensibilidad en la zona de inyección: transitorio. ▸ Efecto Tyndall: coloración azulada superficial; tratable. ▸ Asimetría inicial que puede corregirse con retoque. ▸ Nódulos palpables leves: generalmente se resuelven solos. RIESGOS MAYORES (POCO FRECUENTES) ⚠ Obstrucción vascular (embolismo): riesgo raro pero grave; puede causar necrosis o afectación visual. El médico aplica protocolos de seguridad (aspiración, inyección lenta, cánula). ⚠ Reacción de hipersensibilidad tardía (granuloma): poco frecuente; tratable. ⚠ Biofilm bacteriano o infección: requiere tratamiento antibiótico. ⚠ Migración del producto con el tiempo. ⚠ Asimetría persistente que requiera corrección con hialuronidasa. * El médico aplicará todas las medidas de seguridad disponibles para minimizar los riesgos. La probabilidad de complicaciones graves es baja cuando el procedimiento es realizado por personal médico calificado en instalaciones adecuadas. CONTRAINDICACIONES Este procedimiento NO debe realizarse si el paciente presenta alguna de las siguientes condiciones: ✕ Embarazo o lactancia. ✕ Enfermedades autoinmunes activas o en tratamiento con inmunosupresores. ✕ Alergia conocida al ácido hialurónico. ✕ Infección activa en la zona a tratar. ✕ Trastornos graves de la coagulación. ✕ Tratamiento activo con isotretinoína oral (suspender mínimo 6 meses). ✕ Tendencia a queloides en zona a tratar. ⚠ El paciente declara NO tener ninguna de las contraindicaciones listadas, salvo las que haya notificado explícitamente al médico en su historia clínica. ALTERNATIVAS AL PROCEDIMIENTO El médico ha informado sobre las siguientes alternativas terapéuticas disponibles: ○ Toxina botulínica para arrugas dinámicas. ○ HIFU para tensado y levantamiento. ○ Radiofrecuencia para mejora de calidad cutánea. ○ Cirugía estética (ritidectomía, bichectomía) para resultados permanentes.', 'Evitar aspirina, AINEs, vitamina E y omega-3 al menos 5 días antes. ▸ No consumir alcohol 24 horas antes. ▸ Asistir sin maquillaje. ▸ Evitar tratamientos dentales invasivos 2 semanas antes y después.', 'Aplicar frío local con paño limpio (no hielo directo) si hay edema. ▸ No masajear la zona tratada las primeras 24 a 48 horas. ▸ Evitar calor intenso (sauna, vapor, sol) durante 72 horas. ▸ No realizar ejercicio intenso las primeras 24 horas. ▸ Dormir boca arriba las primeras 1 a 2 noches. ▸ En caso de palidez extrema o dolor intenso: acudir de inmediato a urgencias. ▸ Revisión de seguimiento a los 15 días.', true)
  ON CONFLICT (tratamiento_id) DO UPDATE SET
    titulo = EXCLUDED.titulo,
    texto_consentimiento = EXCLUDED.texto_consentimiento,
    cuidados_pre = EXCLUDED.cuidados_pre,
    cuidados_post = EXCLUDED.cuidados_post;

  INSERT INTO consentimientos (tratamiento_id, titulo, texto_consentimiento, cuidados_pre, cuidados_post, activo)
