  INSERT INTO consentimientos (tratamiento_id, titulo, texto_consentimiento, cuidados_pre, cuidados_post, activo)
  VALUES (47, 'Consentimiento Informado · Masajes y Drenaje Linfático', 'DESCRIPCIÓN DEL PROCEDIMIENTO Los masajes corporales en GIOVAL Medicina Estética incluyen diferentes técnicas adaptadas al objetivo terapéutico del paciente: (1) Drenaje Linfático Manual (DLM): técnica suave y rítmica que estimula el sistema linfático para eliminar toxinas, reducir edema y mejorar el sistema inmune; (2) Masaje Reductor / Modelador: técnica de amasamiento profundo que moviliza el tejido adiposo y mejora la celulitis; (3) Masaje Relajante / Terapéutico: técnica de presión media para aliviar tensión muscular y mejorar la circulación. Los masajes son complementarios a los tratamientos de medicina estética y funcional. BENEFICIOS ESPERADOS ✓ Reducción de edema, retención de líquidos y sensación de pesadez. ✓ Estimulación del sistema linfático y mejora de la circulación. ✓ Mejora de la celulitis y reducción de medidas (masaje reductor). ✓ Alivio de tensión muscular y estrés. ✓ Potenciación de resultados de aparatología corporal. ✓ Mejora del bienestar general y la calidad del sueño. RIESGOS Y POSIBLES COMPLICACIONES RIESGOS MENORES (FRECUENTES Y TRANSITORIOS) ▸ Leve eritema en piel sensible durante o después del masaje. ▸ Sensación de fatiga o somnolencia post-drenaje linfático: normal. ▸ Ligera sed o necesidad de orinar post-drenaje (normal — activación linfática). ▸ Sensibilidad muscular 24 horas después de masaje profundo. RIESGOS MAYORES (POCO FRECUENTES) ⚠ Hematoma o moretón en pieles muy frágiles o con tratamiento anticoagulante. ⚠ Empeoramiento temporal de edema en primeras sesiones de DLM. ⚠ Intolerancia a la presión en pacientes con fibromialgia severa. * El médico aplicará todas las medidas de seguridad disponibles para minimizar los riesgos. La probabilidad de complicaciones graves es baja cuando el procedimiento es realizado por personal médico calificado en instalaciones adecuadas. CONTRAINDICACIONES Este procedimiento NO debe realizarse si el paciente presenta alguna de las siguientes condiciones: ✕ Trombosis venosa profunda activa (contraindicación ABSOLUTA para masaje en extremidades). ✕ Cáncer activo o linfoma (el DLM requiere autorización oncológica). ✕ Infección activa, celulitis infecciosa o heridas abiertas en zona a tratar. ✕ Insuficiencia cardíaca descompensada. ✕ Embarazo (primer trimestre; segundo y tercer trimestre solo DLM suave con autorización médica). ✕ Flebitis activa. ✕ Quemaduras, inflamación severa o lesiones cutáneas en zona a tratar. ✕ Hipertensión severa no controlada. ⚠ El paciente declara NO tener ninguna de las contraindicaciones listadas, salvo las que haya notificado explícitamente al médico en su historia clínica. ALTERNATIVAS AL PROCEDIMIENTO El médico ha informado sobre las siguientes alternativas terapéuticas disponibles: ○ Presoterapia neumática (drenaje linfático mecánico). ○ Aparatología de vacumterapia para celulitis. ○ Actividad física y ejercicio aeróbico para mejoría circulatoria. ○ No realizar el tratamiento.', 'Hidratarse bien (beber 1 a 2 vasos de agua antes del masaje). ▸ No comer en exceso 1 a 2 horas antes. ▸ Informar condiciones médicas, trombosis, varices o medicamentos anticoagulantes. ▸ Usar ropa cómoda o ropa interior desechable proporcionada por la clínica.', 'Beber abundante agua (mínimo 1.5 litros) después del masaje. ▸ Evitar alcohol y alimentos muy salados 24 horas post-drenaje. ▸ Actividad física ligera post-sesión para potenciar la eliminación linfática. ▸ Reportar si aparece enrojecimiento intenso, dolor o edema inusual.', true)
  ON CONFLICT (tratamiento_id) DO UPDATE SET
    titulo = EXCLUDED.titulo,
    texto_consentimiento = EXCLUDED.texto_consentimiento,
    cuidados_pre = EXCLUDED.cuidados_pre,
    cuidados_post = EXCLUDED.cuidados_post;

  INSERT INTO consentimientos (tratamiento_id, titulo, texto_consentimiento, cuidados_pre, cuidados_post, activo)
  VALUES (48, 'Consentimiento Informado · Masajes y Drenaje Linfático', 'DESCRIPCIÓN DEL PROCEDIMIENTO Los masajes corporales en GIOVAL Medicina Estética incluyen diferentes técnicas adaptadas al objetivo terapéutico del paciente: (1) Drenaje Linfático Manual (DLM): técnica suave y rítmica que estimula el sistema linfático para eliminar toxinas, reducir edema y mejorar el sistema inmune; (2) Masaje Reductor / Modelador: técnica de amasamiento profundo que moviliza el tejido adiposo y mejora la celulitis; (3) Masaje Relajante / Terapéutico: técnica de presión media para aliviar tensión muscular y mejorar la circulación. Los masajes son complementarios a los tratamientos de medicina estética y funcional. BENEFICIOS ESPERADOS ✓ Reducción de edema, retención de líquidos y sensación de pesadez. ✓ Estimulación del sistema linfático y mejora de la circulación. ✓ Mejora de la celulitis y reducción de medidas (masaje reductor). ✓ Alivio de tensión muscular y estrés. ✓ Potenciación de resultados de aparatología corporal. ✓ Mejora del bienestar general y la calidad del sueño. RIESGOS Y POSIBLES COMPLICACIONES RIESGOS MENORES (FRECUENTES Y TRANSITORIOS) ▸ Leve eritema en piel sensible durante o después del masaje. ▸ Sensación de fatiga o somnolencia post-drenaje linfático: normal. ▸ Ligera sed o necesidad de orinar post-drenaje (normal — activación linfática). ▸ Sensibilidad muscular 24 horas después de masaje profundo. RIESGOS MAYORES (POCO FRECUENTES) ⚠ Hematoma o moretón en pieles muy frágiles o con tratamiento anticoagulante. ⚠ Empeoramiento temporal de edema en primeras sesiones de DLM. ⚠ Intolerancia a la presión en pacientes con fibromialgia severa. * El médico aplicará todas las medidas de seguridad disponibles para minimizar los riesgos. La probabilidad de complicaciones graves es baja cuando el procedimiento es realizado por personal médico calificado en instalaciones adecuadas. CONTRAINDICACIONES Este procedimiento NO debe realizarse si el paciente presenta alguna de las siguientes condiciones: ✕ Trombosis venosa profunda activa (contraindicación ABSOLUTA para masaje en extremidades). ✕ Cáncer activo o linfoma (el DLM requiere autorización oncológica). ✕ Infección activa, celulitis infecciosa o heridas abiertas en zona a tratar. ✕ Insuficiencia cardíaca descompensada. ✕ Embarazo (primer trimestre; segundo y tercer trimestre solo DLM suave con autorización médica). ✕ Flebitis activa. ✕ Quemaduras, inflamación severa o lesiones cutáneas en zona a tratar. ✕ Hipertensión severa no controlada. ⚠ El paciente declara NO tener ninguna de las contraindicaciones listadas, salvo las que haya notificado explícitamente al médico en su historia clínica. ALTERNATIVAS AL PROCEDIMIENTO El médico ha informado sobre las siguientes alternativas terapéuticas disponibles: ○ Presoterapia neumática (drenaje linfático mecánico). ○ Aparatología de vacumterapia para celulitis. ○ Actividad física y ejercicio aeróbico para mejoría circulatoria. ○ No realizar el tratamiento.', 'Hidratarse bien (beber 1 a 2 vasos de agua antes del masaje). ▸ No comer en exceso 1 a 2 horas antes. ▸ Informar condiciones médicas, trombosis, varices o medicamentos anticoagulantes. ▸ Usar ropa cómoda o ropa interior desechable proporcionada por la clínica.', 'Beber abundante agua (mínimo 1.5 litros) después del masaje. ▸ Evitar alcohol y alimentos muy salados 24 horas post-drenaje. ▸ Actividad física ligera post-sesión para potenciar la eliminación linfática. ▸ Reportar si aparece enrojecimiento intenso, dolor o edema inusual.', true)
  ON CONFLICT (tratamiento_id) DO UPDATE SET
    titulo = EXCLUDED.titulo,
    texto_consentimiento = EXCLUDED.texto_consentimiento,
    cuidados_pre = EXCLUDED.cuidados_pre,
    cuidados_post = EXCLUDED.cuidados_post;

  INSERT INTO consentimientos (tratamiento_id, titulo, texto_consentimiento, cuidados_pre, cuidados_post, activo)
  VALUES (49, 'Consentimiento Informado · Microneedling (Dermapen)', 'DESCRIPCIÓN DEL PROCEDIMIENTO El Dermapen (microneedling) es un procedimiento que utiliza un dispositivo con microagujas que crean microcanales controlados en la piel a profundidades de 0.5 a 2.5 mm. Estos microtraumas estimulan la respuesta natural de reparación de la piel, produciendo colágeno y elastina (neocolagénesis). Los microcanales también permiten una absorción transdermal superior de sueros activos (HA, vitaminas, PDRN, péptidos) aplicados durante el procedimiento. Indicado para cicatrices de acné, poros dilatados, arrugas finas, manchas, pérdida de firmeza y mejoría general de la textura cutánea. BENEFICIOS ESPERADOS ✓ Estimulación de neocolagénesis y elastina para rejuvenecimiento profundo. ✓ Reducción del tamaño de poros dilatados. ✓ Mejoría de cicatrices de acné (atróficas), estrías y cicatrices quirúrgicas. ✓ Mejora de la textura, luminosidad y tono general de la piel. ✓ Reducción de manchas con la aplicación de sueros despigmentantes. ✓ Potenciación de la absorción de principios activos aplicados. ✓ Sin tiempo de recuperación significativo en protocolos superficiales. RIESGOS Y POSIBLES COMPLICACIONES RIESGOS MENORES (FRECUENTES Y TRANSITORIOS) ▸ Eritema (enrojecimiento tipo quemadura solar): normal, dura 24 a 48 horas. ▸ Edema leve en zona tratada: se resuelve en 24 a 72 horas. ▸ Sensibilidad y calor en la piel los primeros días. ▸ Descamación fina en los días siguientes. ▸ Puntos de sangrado mínimo durante el procedimiento (normal en protocolos profundos). RIESGOS MAYORES (POCO FRECUENTES) ⚠ Hiperpigmentación post-inflamatoria: más frecuente en fototipos oscuros; tratable. ⚠ Infección bacteriana o viral (herpes) si no se cumple protocolo de asepsia o cuidados post. ⚠ Cicatrización anormal en pieles predispuestas a queloides. ⚠ Resultado insuficiente o irregular en cicatrices profundas. * El médico aplicará todas las medidas de seguridad disponibles para minimizar los riesgos. La probabilidad de complicaciones graves es baja cuando el procedimiento es realizado por personal médico calificado en instalaciones adecuadas. CONTRAINDICACIONES Este procedimiento NO debe realizarse si el paciente presenta alguna de las siguientes condiciones: ✕ Embarazo o lactancia. ✕ Acné activo en zona a tratar (lesiones pustulosas / nódulos). ✕ Herpes activo en zona a tratar. ✕ Uso de isotretinoína oral (suspender 6 meses antes). ✕ Infección activa, eccema o psoriasis en zona a tratar. ✕ Queloides o cicatrices hipertróficas activas. ✕ Anticoagulantes o trastornos de coagulación (evaluación individualizada). ✕ Rosacea severa activa. ⚠ El paciente declara NO tener ninguna de las contraindicaciones listadas, salvo las que haya notificado explícitamente al médico en su historia clínica. ALTERNATIVAS AL PROCEDIMIENTO El médico ha informado sobre las siguientes alternativas terapéuticas disponibles: ○ Peelings químicos para renovación superficial. ○ Láser fraccionado para resurfacing más profundo. ○ Mesoterapia para aplicación de activos sin microcanales. ○ Radiofrecuencia fraccionada para estimulación de colágeno. ○ No realizar el procedimiento.', 'Asistir con piel limpia y sin maquillaje. ▸ Evitar exposición solar directa 5 días antes y aplicar SPF 50 diariamente. ▸ Suspender retinoides tópicos de alta concentración 5 días antes. ▸ No depilar con cera la zona 48 horas antes. ▸ Informar si hay herpes oral o genital previo. ▸ El médico aplicará crema anestésica tópica 30 a 45 minutos antes del procedimiento.', 'Aplicar la crema reparadora e hidratante indicada por el médico. ▸ Protector solar SPF 50 obligatorio desde el día siguiente; evitar sol directo mínimo 7 días. ▸ No lavar con agua caliente ni usar jabones agresivos las primeras 24 horas. ▸ No aplicar maquillaje durante las primeras 24 a 48 horas. ▸ Evitar actividad física intensa y sauna las primeras 48 horas. ▸ No tocar la zona tratada con manos sin lavar. ▸ Reportar si aparece inflamación excesiva, supuración o fiebre.', true)
  ON CONFLICT (tratamiento_id) DO UPDATE SET
    titulo = EXCLUDED.titulo,
    texto_consentimiento = EXCLUDED.texto_consentimiento,
    cuidados_pre = EXCLUDED.cuidados_pre,
    cuidados_post = EXCLUDED.cuidados_post;

