  INSERT INTO consentimientos (tratamiento_id, titulo, texto_consentimiento, cuidados_pre, cuidados_post, activo)
  VALUES (57, 'Consentimiento Informado · Microinyecciones Faciales', 'DESCRIPCIÓN DEL PROCEDIMIENTO La mesoterapia facial es una técnica de microinyecciones intradérmicas superficiales de cócteles de principios activos específicos para el rostro: vitaminas (C, B complex, biotina), aminoácidos, ácido hialurónico no reticulado, PDRN, glutatión, péptidos bioactivos y agentes despigmentantes (ácido kójico, vitamina C estabilizada, niacinamida, ácido fítico). Las sesiones se realizan con pistola de mesoterapia, aguja napaje o técnica lineal, según el área y objetivo. El protocolo habitual comprende 4 a 8 ses iones con 10 a 21 días de intervalo, seguidas de mantenimiento mensual. BENEFICIOS ESPERADOS ✓ Hidratación intensa y duradera de la piel facial. ✓ Luminosidad y mejora del tono y textura cutánea. ✓ Reducción de manchas y efecto despigmentante (protocolos específicos). ✓ Estimulación de síntesis de colágeno y elastina. ✓ Reducción de arrugas finas y líneas de expresión superficiales. ✓ Mejora del acné leve y reducción de poros. ✓ Resultados naturales y progresivos, compatibles con otros tratamientos. RIESGOS Y POSIBLES COMPLICACIONES RIESGOS MENORES (FRECUENTES Y TRANSITORIOS) ▸ Eritema (enrojecimiento) en zona tratada: normal, dura 2 a 4 horas. ▸ Edema leve y pápulas puntiformes en sitios de inyección: se reabsorben en 12 a 48 horas. ▸ Hematomas puntiformes múltiples: se resuelven en 3 a 7 días. ▸ Sensibilidad o ardor leve durante y después del procedimiento. RIESGOS MAYORES (POCO FRECUENTES) ⚠ Reacción alérgica a algún componente del cóctel: poco frecuente. ⚠ Infección local: muy raro con técnica aséptica adecuada. ⚠ Hiperpigmentación post-inflamatoria en fototipos oscuros. ⚠ Nódulos persistentes (raro con productos correctamente formulados). * El médico aplicará todas las medidas de seguridad disponibles para minimizar los riesgos. La probabilidad de complicaciones graves es baja cuando el procedimiento es realizado por personal médico calificado en instalaciones adecuadas. CONTRAINDICACIONES Este procedimiento NO debe realizarse si el paciente presenta alguna de las siguientes condiciones: ✕ Embarazo o lactancia. ✕ Alergia conocida a algún componente de la formulación. ✕ Infección activa, herpes, acné pustuloso activo o inflamación en zona a tratar. ✕ Trastornos de la coagulación graves. ✕ Enfermedades autoinmunes activas. ✕ Tratamiento activo con inmunosupresores. ⚠ El paciente declara NO tener ninguna de las contraindicaciones listadas, salvo las que haya notificado explícitamente al médico en su historia clínica. ALTERNATIVAS AL PROCEDIMIENTO El médico ha informado sobre las siguientes alternativas terapéuticas disponibles: ○ Dermapen con sueros activos para mayor penetración de activos. ○ Peelings químicos para renovación celular y despigmentación. ○ Skin Boosters (PDRN, HA reticulado) para hidratación profunda. ○ Tratamientos tópicos intensivos (no invasivos). ○ No realizar el procedimiento.', 'Suspender antiinflamatorios 5 días antes (con autorización médica). ▸ Asistir con piel limpia y sin maquillaje. ▸ Hidratarse bien el día previo y el día del procedimiento. ▸ Aplicar FPS 50 diariamente desde 2 semanas antes (especialmente en tratamientos despigmentantes).', 'No tocar ni frotar la zona tratada durante 4 a 6 horas. ▸ No aplicar maquillaje las primeras 12 a 24 horas. ▸ Protector solar SPF 50 obligatorio desde el día siguiente. ▸ Evitar sol, sauna y ejercicio intenso las primeras 24 horas. ▸ Mantener hidratación oral abundante. ▸ Aplicar la crema indicada para potenciar resultados entre sesiones.', true)
  ON CONFLICT (tratamiento_id) DO UPDATE SET
    titulo = EXCLUDED.titulo,
    texto_consentimiento = EXCLUDED.texto_consentimiento,
    cuidados_pre = EXCLUDED.cuidados_pre,
    cuidados_post = EXCLUDED.cuidados_post;

  INSERT INTO consentimientos (tratamiento_id, titulo, texto_consentimiento, cuidados_pre, cuidados_post, activo)
  VALUES (59, 'Consentimiento Informado · Mesoterapia Capilar', 'DESCRIPCIÓN DEL PROCEDIMIENTO Los tratamientos capilares incluyen microinyecciones en el cuero cabelludo de principios activos (oligoelementos, vitaminas, biotina, PDRN, péptidos, HA no reticulado) para fortalecer el folículo, reducir la caída y estimular el crecimiento. El protocolo habitual es de 8 a 12 sesiones semanales o quincenales con mantenimiento posterior. BENEFICIOS ESPERADOS ✓ Reducción visible de la caída del cabello. ✓ Estimulación del crecimiento en zonas con miniaturización folicular. ✓ Fortalecimiento del tallo capilar y mejoría del grosor. ✓ Mejora de la microcirculación del cuero cabelludo. ✓ Complemento ideal para tratamientos sistémicos (minoxidil, finasteride). RIESGOS Y POSIBLES COMPLICACIONES RIESGOS MENORES (FRECUENTES Y TRANSITORIOS) ▸ Dolor leve durante la aplicación en cuero cabelludo. ▸ Eritema y edema leve en zona tratada: 30 a 60 minutos. ▸ Hematomas puntiformes: se reabsorben en 1 a 3 días. ▸ Eflurio telógeno transitorio (mayor caída temporal las primeras semanas): es normal. RIESGOS MAYORES (POCO FRECUENTES) ⚠ Reacción alérgica a algún componente del cóctel. ⚠ Infección en cuero cabelludo: muy raro con técnica aséptica. ⚠ Resultado variable según la etiología de la alopecia. ⚠ Alopecia cicatricial subyacente no diagnosticada que limita el resultado. * El médico aplicará todas las medidas de seguridad disponibles para minimizar los riesgos. La probabilidad de complicaciones graves es baja cuando el procedimiento es realizado por personal médico calificado en instalaciones adecuadas. CONTRAINDICACIONES Este procedimiento NO debe realizarse si el paciente presenta alguna de las siguientes condiciones: ✕ Alopecia cicatricial activa sin tratamiento dermatológico previo. ✕ Infección activa en cuero cabelludo. ✕ Embarazo o lactancia. ✕ Alergia conocida a algún componente del producto. ✕ Trastornos de la coagulación graves. ⚠ El paciente declara NO tener ninguna de las contraindicaciones listadas, salvo las que haya notificado explícitamente al médico en su historia clínica. ALTERNATIVAS AL PROCEDIMIENTO El médico ha informado sobre las siguientes alternativas terapéuticas disponibles: ○ Minoxidil tópico o finasteride oral. ○ PRP capilar como alternativa biológica. ○ Trasplante capilar (FUE/FUT) para alopecias avanzadas. ○ Optimización nutricional y corrección de deficiencias.', 'Asistir con cabello limpio y seco. ▸ Informar todos los medicamentos capilares actuales. ▸ Realizarse los laboratorios capilares indicados.', 'No lavar el cabello durante las primeras 12 horas. ▸ No aplicar productos de peinado las primeras 12 horas. ▸ Evitar exposición solar directa en cuero cabelludo sin protección. ▸ Respetar el esquema de sesiones para resultado óptimo.', true)
  ON CONFLICT (tratamiento_id) DO UPDATE SET
    titulo = EXCLUDED.titulo,
    texto_consentimiento = EXCLUDED.texto_consentimiento,
    cuidados_pre = EXCLUDED.cuidados_pre,
    cuidados_post = EXCLUDED.cuidados_post;

